interfaces.definition:
interface AppLayoutProps {
  children: ReactNode                              // Содержимое страницы
  pageTitle?: string                               // Заголовок страницы
  userName?: string                                // Имя пользователя
  onLogout?: () => void                            // Обработчик выхода из системы
}

interface FloatingAction {
  id: string                                       // Уникальный идентификатор действия
  icon: ReactNode                                  // ReactNode иконки действия
  onClick?: () => void                             // Обработчик клика
  label?: string                                  // Подсказка при наведении
}

interface FloatingActionsProps {
  actions?: FloatingAction[]                        // Массив кастомных действий
}

interface SidebarProps {
  isOpen: boolean                                  // Флаг открытости меню
  onClose: () => void                             // Обработчик закрытия меню
}

interface ThemeProviderProps {
  children: ReactNode                              // Дочерние компоненты
}
